mapper.select:
SELECT id, sender_id, receiver_id, job_id, connection_id, content, created_at, read_at FROM chat_messages WHERE ( (sender_id = #{user1} AND receiver_id = #{user2}) OR (sender_id = #{user2} AND receiver_id = #{user1}) )
AND job_id = #{jobId}
ORDER BY created_at DESC LIMIT 1

SELECT id, sender_id, receiver_id, job_id, connection_id, content, created_at, read_at
FROM chat_messages
WHERE connection_id = #{connectionId}
ORDER BY created_at ASC

    LIMIT #{limit}

SELECT COUNT(*) FROM chat_messages
WHERE connection_id = #{connectionId}
  AND receiver_id = #{receiverId}
  AND read_at IS NULL

SELECT COUNT(*) FROM chat_messages
WHERE receiver_id = #{userId}
  AND sender_id = #{otherUserId}
  AND read_at IS NULL

    AND job_id = #{jobId}
